import "google/protobuf/struct.proto";
import "udpa/annotations/status.proto";
import "validate/validate.proto";

// Custom Header Injection filter configuration for injecting headers into requests and responses.
message CustomHeaderInjection {
  // Request headers to inject. Key is the header name, value is the header value.
